import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.jWxB9oXr.js";const m=JSON.parse('{"title":"Terminal Compatibility Matrix","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Terminal Compatibility Matrix"}],["meta",{"property":"og:description","content":"Terminal Compatibility Matrix — Silvery reference documentation with detailed API information."}],["meta",{"property":"og:url","content":"https://silvery.dev/reference/terminal-matrix.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/reference/terminal-matrix.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://silvery.dev/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Terminal Compatibility Matrix\\",\\"item\\":\\"https://silvery.dev/reference/terminal-matrix\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Terminal Compatibility Matrix\\",\\"description\\":\\"Terminal Compatibility Matrix — Silvery reference documentation with detailed API information.\\",\\"url\\":\\"https://silvery.dev/reference/terminal-matrix.html\\",\\"dateModified\\":\\"2026-04-01T05:05:39.000Z\\",\\"datePublished\\":\\"2026-04-01T05:05:39.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"reference/terminal-matrix.md","filePath":"reference/terminal-matrix.md","lastUpdated":1775019939000}'),o={name:"reference/terminal-matrix.md"};function s(d,t,l,n,c,p){return a(),i("div",null,[...t[0]||(t[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /reference/terminal-matrix.md for this page in Markdown format</div><h1 id="terminal-compatibility-matrix" tabindex="-1">Terminal Compatibility Matrix <a class="header-anchor" href="#terminal-compatibility-matrix" aria-label="Permalink to &quot;Terminal Compatibility Matrix&quot;">​</a></h1><p><em>Terminal capabilities last verified: 2026-03.</em></p><p>Comprehensive reference of terminal emulator feature support as detected by Silvery.</p><h2 id="capability-matrix" tabindex="-1">Capability Matrix <a class="header-anchor" href="#capability-matrix" aria-label="Permalink to &quot;Capability Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Terminal</th><th>Colors</th><th>Kitty KB</th><th>Kitty Gfx</th><th>Sixel</th><th><a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></th><th>Hyperlinks</th><th>Notify</th><th>Paste</th><th>Mouse</th><th>Sync</th><th>Unicode</th></tr></thead><tbody><tr><td>Ghostty</td><td>24-bit</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>kitty</td><td>24-bit</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>WezTerm</td><td>24-bit</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td><a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a></td><td>24-bit</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>foot</td><td>24-bit</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Alacritty</td><td>24-bit</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>VS Code</td><td>24-bit</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td></tr><tr><td>Terminal.app</td><td>256</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td></tr><tr><td>tmux</td><td>24-bit*</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td></tr><tr><td>TERM=dumb</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>-</td><td>Yes</td><td>Yes</td><td>-</td><td>Yes</td></tr></tbody></table><p>* tmux color support depends on the outer terminal and tmux configuration.</p><p>For comprehensive, feature-by-feature terminal compatibility data beyond what Silvery detects, see <a href="https://terminfo.dev" target="_blank" rel="noreferrer">terminfo.dev</a>.</p><h2 id="column-descriptions" tabindex="-1">Column Descriptions <a class="header-anchor" href="#column-descriptions" aria-label="Permalink to &quot;Column Descriptions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Protocol/Standard</th><th>Description</th></tr></thead><tbody><tr><td>Colors</td><td>SGR</td><td>Color depth: 24-bit (truecolor), 256, 16 (basic), or none</td></tr><tr><td>Kitty KB</td><td>CSI &gt; u</td><td><a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a> for unambiguous key identification</td></tr><tr><td>Kitty Gfx</td><td>APC G</td><td>Kitty graphics protocol for inline image display</td></tr><tr><td>Sixel</td><td>DCS q</td><td>Sixel graphics for inline image display</td></tr><tr><td><a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></td><td><a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></td><td>Clipboard access (works over SSH)</td></tr><tr><td>Hyperlinks</td><td><a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Hyperlink escape sequence — makes text clickable in supporting terminals.">OSC 8</a></td><td>Clickable hyperlinks in terminal output</td></tr><tr><td>Notify</td><td>OSC 9/99</td><td>Desktop notifications (OSC 9 = <a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a>, OSC 99 = Kitty)</td></tr><tr><td>Paste</td><td>DEC 2004</td><td>Bracketed paste mode (distinguish pasted from typed input)</td></tr><tr><td>Mouse</td><td>SGR 1006</td><td><a href="/guide/event-handling" class="hover-link" data-tooltip="Extended mouse protocol (mode 1006) — reports coordinates beyond column 223, supports press/release/drag/wheel events.">SGR mouse</a> tracking (click, drag, scroll)</td></tr><tr><td>Sync</td><td>DEC 2026</td><td>Synchronized output (batch rendering to prevent tearing)</td></tr><tr><td>Unicode</td><td>-</td><td>Unicode and emoji rendering</td></tr></tbody></table><h2 id="terminal-details" tabindex="-1">Terminal Details <a class="header-anchor" href="#terminal-details" aria-label="Permalink to &quot;Terminal Details&quot;">​</a></h2><h3 id="ghostty" tabindex="-1">Ghostty <a class="header-anchor" href="#ghostty" aria-label="Permalink to &quot;Ghostty&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=ghostty</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: Full <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a> (Cmd, Hyper, event types)</li><li><strong>Images</strong>: Kitty graphics protocol</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a> (works over SSH)</li><li><strong>Notes</strong>: Modern GPU-accelerated terminal. No OSC 9/99 notifications.</li></ul><h3 id="kitty" tabindex="-1">kitty <a class="header-anchor" href="#kitty" aria-label="Permalink to &quot;kitty&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM=xterm-kitty</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: Full <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a> (originator of the spec)</li><li><strong>Images</strong>: Kitty graphics protocol (originator of the spec)</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></li><li><strong>Notifications</strong>: OSC 99</li><li><strong>Notes</strong>: Feature-rich terminal, defines many protocols used by others.</li></ul><h3 id="wezterm" tabindex="-1">WezTerm <a class="header-anchor" href="#wezterm" aria-label="Permalink to &quot;WezTerm&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=WezTerm</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a></li><li><strong>Images</strong>: Sixel graphics</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></li><li><strong>Notes</strong>: Cross-platform (macOS, Linux, Windows). Also supports <a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a> image protocol.</li></ul><h3 id="iterm2" tabindex="-1">iTerm2 <a class="header-anchor" href="#iterm2" aria-label="Permalink to &quot;iTerm2&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=iTerm.app</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: Legacy xterm sequences only (no Kitty protocol)</li><li><strong>Images</strong>: Proprietary <a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a> inline image protocol (not Kitty or Sixel)</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></li><li><strong>Notifications</strong>: OSC 9</li><li><strong>Notes</strong>: macOS only. Most popular macOS terminal after Terminal.app.</li></ul><h3 id="foot" tabindex="-1">foot <a class="header-anchor" href="#foot" aria-label="Permalink to &quot;foot&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM=foot</code> or <code>TERM=foot-extra</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a></li><li><strong>Images</strong>: Sixel graphics</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></li><li><strong>Notes</strong>: Wayland-native, minimalist, fast. Linux only.</li></ul><h3 id="alacritty" tabindex="-1">Alacritty <a class="header-anchor" href="#alacritty" aria-label="Permalink to &quot;Alacritty&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=Alacritty</code>, <code>COLORTERM=truecolor</code></li><li><strong>Keyboard</strong>: Legacy xterm sequences only</li><li><strong>Images</strong>: None (no image protocol support)</li><li><strong>Clipboard</strong>: <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a></li><li><strong>Notes</strong>: GPU-accelerated, cross-platform. Focused on performance over features. Sync output since 0.14.</li></ul><h3 id="vs-code-integrated-terminal" tabindex="-1">VS Code Integrated Terminal <a class="header-anchor" href="#vs-code-integrated-terminal" aria-label="Permalink to &quot;VS Code Integrated Terminal&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=vscode</code>, <code>COLORTERM=truecolor</code></li><li><strong>Notes</strong>: Embedded terminal in VS Code. Basic capabilities. xterm.js-based.</li></ul><h3 id="terminal-app-macos" tabindex="-1">Terminal.app (macOS) <a class="header-anchor" href="#terminal-app-macos" aria-label="Permalink to &quot;Terminal.app (macOS)&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM_PROGRAM=Apple_Terminal</code>, <code>TERM=xterm-256color</code></li><li><strong>Colors</strong>: 256 only (no truecolor)</li><li><strong>Notes</strong>: macOS built-in. Most limited of common terminals. No <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a>, no hyperlinks.</li></ul><h3 id="tmux" tabindex="-1">tmux <a class="header-anchor" href="#tmux" aria-label="Permalink to &quot;tmux&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM=tmux-256color</code>, also <code>TMUX</code> env var set</li><li><strong>Colors</strong>: Passes through outer terminal&#39;s color support (configure with <code>set -as terminal-features &quot;,*:RGB&quot;</code>)</li><li><strong>Keyboard</strong>: Does not pass through <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a></li><li><strong>Notes</strong>: Terminal multiplexer. Capabilities largely depend on the outer terminal and configuration. Use <code>set -sg escape-time 0</code> for responsive input.</li></ul><h3 id="ci-headless-term-dumb" tabindex="-1">CI / Headless (TERM=dumb) <a class="header-anchor" href="#ci-headless-term-dumb" aria-label="Permalink to &quot;CI / Headless (TERM=dumb)&quot;">​</a></h3><ul><li><strong>Env</strong>: <code>TERM=dumb</code> or no TERM set</li><li><strong>Notes</strong>: No advanced capabilities. Use <code>renderString()</code> with <code>plain: true</code> for clean output.</li></ul><h2 id="detection-method" tabindex="-1">Detection Method <a class="header-anchor" href="#detection-method" aria-label="Permalink to &quot;Detection Method&quot;">​</a></h2><p>Silvery detects capabilities synchronously from environment variables at startup:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>TERM</code></td><td>Terminal type (e.g., <code>xterm-256color</code>, <code>xterm-kitty</code>)</td></tr><tr><td><code>TERM_PROGRAM</code></td><td>Terminal emulator name (e.g., <code>ghostty</code>, <code>iTerm.app</code>)</td></tr><tr><td><code>COLORTERM</code></td><td>Color capability hint (<code>truecolor</code> or <code>24bit</code>)</td></tr><tr><td><code>NO_COLOR</code></td><td>Disable all color output when set</td></tr></tbody></table><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { detectTerminalCaps } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@silvery/ag-term&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> caps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> detectTerminalCaps</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// caps.colorLevel, caps.kittyKeyboard, caps.osc52, etc.</span></span></code></pre></div><p>No I/O is performed -- detection is instant but limited to what env vars reveal. For runtime detection of specific protocols (like <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Extended keyboard protocol with 5 flags — disambiguate, event types, alternate keys, all keys, associated text. Enables modifier detection and key release events.">Kitty keyboard</a> support), use:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { detectKittyFromStdio } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@silvery/ag-term&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> detectKittyFromStdio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(process.stdout, process.stdin, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// result.supported: boolean, result.flags: number</span></span></code></pre></div><h2 id="generating-the-matrix" tabindex="-1">Generating the Matrix <a class="header-anchor" href="#generating-the-matrix" aria-label="Permalink to &quot;Generating the Matrix&quot;">​</a></h2><p>The compatibility matrix can also be auto-generated from the detection code:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor/silvery/tests/terminal-compat/compat-matrix.ts</span></span></code></pre></div><p>This runs <code>detectTerminalCaps()</code> with mocked env vars for each terminal profile and outputs a markdown table.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://www.ecma-international.org/publications-and-standards/standards/ecma-48/" target="_blank" rel="noreferrer">ECMA-48 / ISO 6429</a> -- CSI/OSC standard</li><li><a href="https://invisible-island.net/xterm/ctlseqs/ctlseqs.html" target="_blank" rel="noreferrer">XTerm Control Sequences</a> -- de facto terminal standard</li><li><a href="https://sw.kovidgoyal.net/kitty/keyboard-protocol/" target="_blank" rel="noreferrer">Kitty Keyboard Protocol</a></li><li><a href="https://sw.kovidgoyal.net/kitty/graphics-protocol/" target="_blank" rel="noreferrer">Kitty Graphics Protocol</a></li><li><a href="https://en.wikipedia.org/wiki/Sixel" target="_blank" rel="noreferrer">Sixel Graphics</a></li><li><a href="https://gist.github.com/egmontkob/eb114294efbcd5adb1944c9f3cb5feda" target="_blank" rel="noreferrer">OSC 8 Hyperlinks</a></li><li><a href="https://gist.github.com/christianparpart/d8a62cc1ab659194337d73e399004036" target="_blank" rel="noreferrer">Synchronized Output</a></li><li><a href="https://cirw.in/blog/bracketed-paste" target="_blank" rel="noreferrer">Bracketed Paste</a></li><li><a href="https://no-color.org/" target="_blank" rel="noreferrer">NO_COLOR Standard</a></li></ul>`,43)])])}const u=e(o,[["render",s]]);export{m as __pageData,u as default};
